let TotalLoads = toscalar(
    customEvents
    | where timestamp {TimeRange}
    | where name == "Past Trustees Section Viewed"
    | count
);
let WithHistory = toscalar(
    customEvents
    | where timestamp {TimeRange}
    | where name == "Past Trustees Section Viewed"
    | where toint(customMeasurements.historyCount) > 0
    | count
);
print
    TotalLoads = TotalLoads,
    WithHistory = WithHistory,
    PctWithHistory = round(iif(TotalLoads > 0, todouble(WithHistory) / todouble(TotalLoads) * 100, 0.0), 1)

let TotalSectionViews = toscalar(
    customEvents
    | where timestamp {TimeRange}
    | where name == "Past Trustees Section Viewed"
    | where toint(customMeasurements.historyCount) > 0
    | count
);
let NameLinkClicks = toscalar(
    customEvents
    | where timestamp {TimeRange}
    | where name == "Past Trustee Profile Navigated"
    | count
);
print
    SectionViewsWithHistory = TotalSectionViews,
    NameLinkClicks = NameLinkClicks,
    ClickThroughRate = round(iif(TotalSectionViews > 0, todouble(NameLinkClicks) / todouble(TotalSectionViews) * 100, 0.0), 1)
